<?php
namespace App\Controllers;
use App\Config\Database;use App\Helpers\Auth;
final class ReportController {public function export(string $type):void{Auth::requireAdmin();$db=Database::connection();$maps=['top'=>"SELECT cancion,artista,reproducciones FROM vw_top_canciones_30_dias LIMIT 10",'generos'=>"SELECT g.nombre genero,COUNT(r.id) reproducciones FROM generos g LEFT JOIN canciones c ON c.genero_id=g.id LEFT JOIN reproducciones r ON r.cancion_id=c.id GROUP BY g.id,g.nombre ORDER BY reproducciones DESC",'ventas'=>"SELECT DATE_FORMAT(fecha_hora,'%Y-%m') mes,COUNT(*) transacciones,SUM(subtotal) subtotal,SUM(itbms) itbms,SUM(total) total FROM compras GROUP BY mes ORDER BY mes DESC",'eventos'=>"SELECT e.nombre evento,e.fecha,e.capacidad,COALESCE(SUM(en.cantidad),0) entradas_vendidas,COALESCE(SUM(en.total),0) ingresos FROM eventos e LEFT JOIN entradas en ON en.evento_id=e.id GROUP BY e.id ORDER BY e.fecha DESC"];$sql=$maps[$type]??null;if(!$sql)throw new \RuntimeException();$rows=$db->query($sql)->fetchAll();header('Content-Type: text/csv; charset=UTF-8');header('Content-Disposition: attachment; filename="reporte_'.$type.'_'.date('Ymd').'.csv"');echo "\xEF\xBB\xBF";$o=fopen('php://output','w');if($rows)fputcsv($o,array_keys($rows[0]),';');foreach($rows as $row)fputcsv($o,$row,';');fclose($o);}}
